import { t } from "../shared/i18n";
import type { QueueTask, SendTaskResult } from "../shared/types";

const FLOATING_ROOT_ID = "claude-queue-resumer-floating-root";
const RESPONSE_WAIT_TIMEOUT_MS = 6 * 60 * 1000;
const RESPONSE_STABLE_MS = 3500;

function isVisible(element: Element): boolean {
  const rect = element.getBoundingClientRect();
  const style = window.getComputedStyle(element);
  return rect.width > 0 && rect.height > 0 && style.visibility !== "hidden" && style.display !== "none";
}

function sleep(ms: number): Promise<void> {
  return new Promise((resolve) => window.setTimeout(resolve, ms));
}

function getEditableText(element: HTMLElement): string {
  if (element instanceof HTMLTextAreaElement || element instanceof HTMLInputElement) {
    return element.value;
  }
  return element.innerText || element.textContent || "";
}

function findInputElement(): HTMLElement | null {
  const candidates = [
    ...document.querySelectorAll<HTMLElement>('div[contenteditable="true"], [role="textbox"], textarea')
  ].filter((element) => {
    if (!isVisible(element)) return false;
    if (element instanceof HTMLTextAreaElement && element.disabled) return false;
    if (element.getAttribute("aria-disabled") === "true") return false;
    return true;
  });

  return (
    candidates
      .map((element) => {
        const rect = element.getBoundingClientRect();
        const text = `${element.getAttribute("aria-label") ?? ""} ${element.getAttribute("placeholder") ?? ""} ${element.getAttribute("data-placeholder") ?? ""}`.toLowerCase();
        let score = rect.bottom;
        if (/(reply|prompt|message|ask|send|输入|消息)/.test(text)) score += 500;
        if (/(search|title|name|filter|rename)/.test(text)) score -= 800;
        if (element instanceof HTMLTextAreaElement) score += 160;
        if (element.isContentEditable) score += 120;
        if (rect.height < 24 || rect.width < 180) score -= 500;
        return { element, score };
      })
      .sort((a, b) => b.score - a.score)[0]?.element ?? null
  );
}

function dispatchEditableEvents(element: HTMLElement): void {
  const data = getEditableText(element);
  element.dispatchEvent(new InputEvent("beforeinput", { bubbles: true, inputType: "insertText", data }));
  element.dispatchEvent(new InputEvent("input", { bubbles: true, inputType: "insertText", data }));
  element.dispatchEvent(new Event("change", { bubbles: true }));
  element.dispatchEvent(new KeyboardEvent("keyup", { bubbles: true, key: "Unidentified" }));
  element.dispatchEvent(new CompositionEvent("compositionend", { bubbles: true }));
}

function fillInput(element: HTMLElement, content: string): void {
  element.focus();

  if (element instanceof HTMLTextAreaElement || element instanceof HTMLInputElement) {
    const setter = Object.getOwnPropertyDescriptor(element.constructor.prototype, "value")?.set;
    setter?.call(element, content);
    dispatchEditableEvents(element);
    return;
  }

  const selection = window.getSelection();
  const range = document.createRange();
  range.selectNodeContents(element);
  selection?.removeAllRanges();
  selection?.addRange(range);

  const inserted = document.execCommand("insertText", false, content);
  if (!inserted) {
    element.textContent = content;
  }
  dispatchEditableEvents(element);
}

function isEnabledButton(button: HTMLButtonElement): boolean {
  return !button.disabled && button.getAttribute("aria-disabled") !== "true";
}

function getButtonLabel(button: HTMLButtonElement): string {
  return `${button.getAttribute("aria-label") ?? ""} ${button.title ?? ""} ${button.innerText ?? ""} ${button.dataset.testid ?? ""}`.toLowerCase();
}

function buttonLooksLikeSend(button: HTMLButtonElement): boolean {
  const label = getButtonLabel(button);
  if (/(send|submit|发送|送出)/.test(label)) return true;
  if (/(attach|upload|image|file|mic|voice|stop|cancel|pause|tools?|model|settings|menu|dictate|browse)/.test(label)) return false;

  const svgText = [...button.querySelectorAll("svg")]
    .map((svg) => `${svg.getAttribute("aria-label") ?? ""} ${svg.getAttribute("data-icon") ?? ""} ${svg.className}`)
    .join(" ")
    .toLowerCase();
  if (/(send|arrow-up|paper-plane|send-horizontal)/.test(svgText)) return true;

  const rect = button.getBoundingClientRect();
  return Boolean(button.querySelector("svg")) && rect.width <= 64 && rect.height <= 64;
}

function buttonLooksLikeStop(button: HTMLButtonElement): boolean {
  const label = getButtonLabel(button);
  if (/(stop|cancel|pause|停止|中止|取消)/.test(label)) return true;

  const svgText = [...button.querySelectorAll("svg")]
    .map((svg) => `${svg.getAttribute("aria-label") ?? ""} ${svg.getAttribute("data-icon") ?? ""} ${svg.className}`)
    .join(" ")
    .toLowerCase();
  return /(stop|square|pause|cancel)/.test(svgText);
}

function isClaudeBusy(): boolean {
  if (document.querySelector('[aria-busy="true"]')) return true;
  const buttons = [...document.querySelectorAll<HTMLButtonElement>("button")].filter((button) => isVisible(button) && isEnabledButton(button));
  if (buttons.some(buttonLooksLikeStop)) return true;

  const busyElements = [...document.querySelectorAll<HTMLElement>("[aria-label], [title], [data-state]")].filter(isVisible);
  return busyElements.some((element) => {
    const label = `${element.getAttribute("aria-label") ?? ""} ${element.getAttribute("title") ?? ""} ${element.getAttribute("data-state") ?? ""}`.toLowerCase();
    return /(generating|thinking|loading|response in progress|正在生成|思考中|生成中)/.test(label);
  });
}

function getPageTextSnapshot(): string {
  const main = document.querySelector<HTMLElement>("main") ?? document.body;
  const clone = main.cloneNode(true) as HTMLElement;
  clone.querySelector(`#${FLOATING_ROOT_ID}`)?.remove();
  return (clone.innerText || clone.textContent || "").replace(/\s+/g, " ").trim();
}

function composerLooksReady(): boolean {
  const input = findInputElement();
  return Boolean(input && getEditableText(input).trim().length === 0);
}

function findComposerRoot(input: HTMLElement): HTMLElement {
  const candidates: HTMLElement[] = [];
  let current: HTMLElement | null = input;
  for (let depth = 0; current && depth < 8; depth += 1) {
    candidates.push(current);
    current = current.parentElement;
  }
  return (
    candidates.find((element) => {
      const buttons = [...element.querySelectorAll<HTMLButtonElement>("button")].filter((button) => isVisible(button) && isEnabledButton(button));
      return buttons.some(buttonLooksLikeSend);
    }) ?? input.closest("form") ?? input.parentElement ?? document.body
  );
}

function findSendButton(input: HTMLElement): HTMLButtonElement | null {
  const composer = findComposerRoot(input);
  const scopedButtons = [...composer.querySelectorAll<HTMLButtonElement>("button")].filter((button) => isVisible(button) && isEnabledButton(button));
  const scopedSend = scopedButtons.find(buttonLooksLikeSend);
  if (scopedSend) return scopedSend;

  const allButtons = [...document.querySelectorAll<HTMLButtonElement>("button")].filter((button) => isVisible(button) && isEnabledButton(button));
  return allButtons.find(buttonLooksLikeSend) ?? null;
}

async function waitForSendButton(input: HTMLElement): Promise<HTMLButtonElement | null> {
  const startedAt = Date.now();
  while (Date.now() - startedAt < 2500) {
    const button = findSendButton(input);
    if (button) return button;
    await sleep(100);
  }
  return null;
}

function pressSendShortcut(input: HTMLElement): void {
  input.focus();
  for (const init of [
    { key: "Enter", code: "Enter", bubbles: true, cancelable: true },
    { key: "Enter", code: "Enter", bubbles: true, cancelable: true, metaKey: true },
    { key: "Enter", code: "Enter", bubbles: true, cancelable: true, ctrlKey: true }
  ]) {
    input.dispatchEvent(new KeyboardEvent("keydown", init));
    input.dispatchEvent(new KeyboardEvent("keyup", init));
  }
}

async function waitForSubmissionEvidence(originalInput: HTMLElement, beforeUrl: string): Promise<boolean> {
  const startedAt = Date.now();
  while (Date.now() - startedAt < 3000) {
    const currentInput = findInputElement() ?? originalInput;
    const text = getEditableText(currentInput).trim();
    if (text.length === 0) return true;
    if (window.location.href !== beforeUrl && /\/chat\//.test(window.location.pathname)) return true;
    if (!document.documentElement.contains(originalInput)) return true;
    await sleep(150);
  }
  return false;
}

async function waitForConversationUrl(beforeUrl: string, task?: QueueTask): Promise<string | undefined> {
  if (/\/chat\//.test(window.location.pathname)) return window.location.href;
  if (task?.conversationMode !== "new") return /\/chat\//.test(new URL(beforeUrl).pathname) ? beforeUrl : undefined;

  const startedAt = Date.now();
  while (Date.now() - startedAt < 8000) {
    if (/\/chat\//.test(window.location.pathname)) return window.location.href;
    await sleep(200);
  }
  return undefined;
}

function elementLooksLikeNewChat(element: HTMLElement): boolean {
  const label = `${element.getAttribute("aria-label") ?? ""} ${element.getAttribute("title") ?? ""} ${element.innerText ?? ""}`.toLowerCase();
  if (/(new chat|new conversation|start chat|新对话|新聊天|开始新)/.test(label)) return true;
  if (element instanceof HTMLAnchorElement && /\/new(?:[/?#]|$)/.test(element.href)) return true;
  return false;
}

async function prepareNewConversation(): Promise<boolean> {
  if (/\/new(?:[/?#]|$)/.test(window.location.pathname)) return true;

  const candidates = [
    ...document.querySelectorAll<HTMLElement>('a[href*="/new"], button, [role="button"], a')
  ].filter((element) => isVisible(element) && elementLooksLikeNewChat(element));

  const target = candidates[0];
  if (target) {
    target.click();
    await sleep(900);
    return Boolean(findInputElement());
  }

  try {
    history.pushState(null, "", "/new");
    window.dispatchEvent(new PopStateEvent("popstate"));
    await sleep(900);
    return Boolean(findInputElement());
  } catch {
    return false;
  }
}

export async function waitForClaudeResponseComplete(): Promise<void> {
  await sleep(1500);

  const startedAt = Date.now();
  let lastSnapshot = getPageTextSnapshot();
  let stableSince = Date.now();

  while (Date.now() - startedAt < RESPONSE_WAIT_TIMEOUT_MS) {
    const snapshot = getPageTextSnapshot();
    if (snapshot !== lastSnapshot) {
      lastSnapshot = snapshot;
      stableSince = Date.now();
    }

    if (!isClaudeBusy() && composerLooksReady() && Date.now() - stableSince >= RESPONSE_STABLE_MS) {
      return;
    }

    await sleep(900);
  }
}

export async function sendTaskToClaude(taskContent: string, task?: QueueTask): Promise<SendTaskResult> {
  if (task?.conversationMode === "new") {
    const ready = await prepareNewConversation();
    if (!ready) return { ok: false, error: t("sender.cannot_open_new") };
  }

  const input = findInputElement();
  if (!input) return { ok: false, error: t("sender.no_input") };

  if (getEditableText(input).trim().length > 0) {
    return { ok: false, error: "INPUT_NOT_EMPTY" };
  }

  const beforeUrl = window.location.href;
  fillInput(input, taskContent);
  await sleep(350);

  const button = await waitForSendButton(input);
  if (button) {
    button.focus();
    button.dispatchEvent(new MouseEvent("mousedown", { bubbles: true, cancelable: true }));
    button.dispatchEvent(new MouseEvent("mouseup", { bubbles: true, cancelable: true }));
    button.click();
  } else {
    pressSendShortcut(input);
  }

  if (!(await waitForSubmissionEvidence(input, beforeUrl))) {
    pressSendShortcut(input);
  }

  const hasEvidence = await waitForSubmissionEvidence(input, beforeUrl);
  const conversationUrl = await waitForConversationUrl(beforeUrl, task);
  const conversationTitle = task?.conversationTitle;

  return hasEvidence
    ? { ok: true, submitted: true, conversationUrl, conversationTitle }
    : { ok: false, submitted: true, conversationUrl, conversationTitle, error: t("sender.submit_no_confirm") };
}
