import { detectClaudeLimitState } from "./claudeDetector";
import { initFloatingPanel, refreshFloatingPanel, showFloatingPanel } from "./floatingPanel";
import { sendTaskToClaude, waitForClaudeResponseComplete } from "./claudeSender";
import type { RuntimeMessage } from "../shared/types";

let lastSerializedDetection = "";
let debounceTimer: number | undefined;
let detectionInterval: number | undefined;
let initialDetectionTimer: number | undefined;
let extensionContextInvalidated = false;

function isExtensionContextInvalidated(error: unknown): boolean {
  return error instanceof Error && /Extension context invalidated/i.test(error.message);
}

function stopContentScriptTimers(): void {
  extensionContextInvalidated = true;
  observer.disconnect();
  if (debounceTimer !== undefined) window.clearTimeout(debounceTimer);
  if (initialDetectionTimer !== undefined) window.clearTimeout(initialDetectionTimer);
  if (detectionInterval !== undefined) window.clearInterval(detectionInterval);
}

function sendRuntimeMessage(message: RuntimeMessage): void {
  if (extensionContextInvalidated) return;
  try {
    chrome.runtime.sendMessage(message).catch((error) => {
      if (isExtensionContextInvalidated(error)) {
        stopContentScriptTimers();
      }
    });
  } catch (error) {
    if (isExtensionContextInvalidated(error)) {
      stopContentScriptTimers();
      return;
    }
    throw error;
  }
}

function sendDetection(): void {
  if (extensionContextInvalidated) return;
  const detection = detectClaudeLimitState();
  const serialized = JSON.stringify({
    limitStatus: detection.limitStatus,
    resetAt: detection.resetAt,
    resetText: detection.resetText,
    usageText: detection.usageText
  });

  if (serialized === lastSerializedDetection) return;
  lastSerializedDetection = serialized;

  sendRuntimeMessage({ type: "CONTENT_STATUS", detection } satisfies RuntimeMessage);
}

function scheduleDetection(): void {
  if (extensionContextInvalidated) return;
  if (debounceTimer) window.clearTimeout(debounceTimer);
  debounceTimer = window.setTimeout(sendDetection, 350);
}

const observer = new MutationObserver(scheduleDetection);
observer.observe(document.documentElement, {
  childList: true,
  subtree: true,
  characterData: true
});

initialDetectionTimer = window.setTimeout(sendDetection, 500);
detectionInterval = window.setInterval(sendDetection, 30_000);
initFloatingPanel();

window.addEventListener("pageshow", () => {
  sendDetection();
  void refreshFloatingPanel(true).catch((error) => {
    if (isExtensionContextInvalidated(error)) stopContentScriptTimers();
  });
});

chrome.runtime.onMessage.addListener((message: RuntimeMessage, _sender, sendResponse) => {
  if (message.type === "PING") {
    sendResponse({ ok: true });
    return false;
  }

  if (message.type === "DETECT_NOW") {
    const detection = detectClaudeLimitState();
    sendRuntimeMessage({ type: "CONTENT_STATUS", detection } satisfies RuntimeMessage);
    sendResponse({ ok: true, detection });
    return false;
  }

  if (message.type === "SHOW_FLOATING_PANEL") {
    showFloatingPanel();
    sendDetection();
    sendResponse({ ok: true });
    return false;
  }

  if (message.type === "SEND_TASK") {
    sendTaskToClaude(message.content, message.task).then(sendResponse).catch((error) => {
      sendResponse({ ok: false, error: error instanceof Error ? error.message : String(error) });
    });
    return true;
  }

  if (message.type === "WAIT_FOR_CLAUDE_RESPONSE_COMPLETE") {
    waitForClaudeResponseComplete().then(() => sendResponse({ ok: true })).catch((error) => {
      sendResponse({ ok: false, error: error instanceof Error ? error.message : String(error) });
    });
    return true;
  }

  return false;
});
