export interface UsageWindow {
  utilization: number;
  resetsAt?: number;
}

export interface UsageSnapshot {
  fiveHour?: UsageWindow;
  weekly?: UsageWindow;
  updatedAt: number;
}

function clampPercent(value: number): number {
  return Math.max(0, Math.min(100, value));
}

function readNumericField(record: Record<string, unknown>, keys: string[]): number | undefined {
  for (const key of keys) {
    const value = record[key];
    if (typeof value === "number" && Number.isFinite(value)) return value;
  }
  return undefined;
}

function normalizeUsagePercent(record: Record<string, unknown>): number | undefined {
  const percentValue = readNumericField(record, ["percent_used", "percentage", "used_percentage"]);
  if (percentValue !== undefined) return clampPercent(percentValue);

  const utilization = record.utilization;
  if (typeof utilization !== "number" || !Number.isFinite(utilization)) return undefined;
  return clampPercent(utilization > 0 && utilization < 1 ? utilization * 100 : utilization);
}

export function normalizeUsageWindow(value: unknown): UsageWindow | undefined {
  if (!value || typeof value !== "object") return undefined;
  const record = value as Record<string, unknown>;
  const utilization = normalizeUsagePercent(record);
  if (utilization === undefined) return undefined;
  const rawReset = record.resets_at ?? record.reset_at ?? record.resetAt;
  const resetsAt =
    typeof rawReset === "string"
      ? Date.parse(rawReset)
      : typeof rawReset === "number" && Number.isFinite(rawReset)
        ? rawReset < 10_000_000_000
          ? rawReset * 1000
          : rawReset
        : undefined;
  return {
    utilization,
    resetsAt: resetsAt && Number.isFinite(resetsAt) ? resetsAt : undefined
  };
}

export function parseUsagePayload(payload: unknown): UsageSnapshot | undefined {
  if (!payload || typeof payload !== "object") return undefined;
  const record = payload as Record<string, unknown>;
  const windows = typeof record.windows === "object" && record.windows ? (record.windows as Record<string, unknown>) : undefined;
  const fiveHour = normalizeUsageWindow(record.five_hour ?? record.fiveHour ?? record.session ?? windows?.["5h"]);
  const weekly = normalizeUsageWindow(record.seven_day ?? record.sevenDay ?? record.weekly ?? windows?.["7d"]);
  if (!fiveHour && !weekly) return undefined;
  return {
    fiveHour,
    weekly,
    updatedAt: Date.now()
  };
}
